$(document).ready(function(){var o=$("#menu"),e=$(".header__menu-toggle"),s=$(".menu__close");$(e).on("click",function(e){e.preventDefault(),o.toggleClass("active")}),$(s).on("click touchstart",function(e){e.preventDefault(),o.removeClass("active")}),$(".events").slick({autoplay:!0,arrows:!0,slidesToShow:4,slidesToScroll:1,infinite:!1,pauseOnFocus:!1,pauseOnHover:!1,responsive:[{breakpoint:991,settings:{slidesToShow:3}},{breakpoint:767,settings:{slidesToShow:2}},{breakpoint:575,settings:{slidesToShow:1}}]}),$(".gallery").slick(),$(".gallery-skew").slick({autoplay:!0,arrows:!0,pauseOnFocus:!1,pauseOnHover:!1,prevArrow:".arrow__prev",nextArrow:".arrow__next",fade:!0}),$(".main-gallery-nav").slick({autoplay:!1,arrows:!1,slidesToShow:4,slidesToScroll:1,infinite:!1,pauseOnFocus:!1,pauseOnHover:!1,focusOnSelect:!0,responsive:[{breakpoint:991,settings:{slidesToShow:3}},{breakpoint:575,settings:{slidesToShow:2}}]}),$(".info > div > a").on("click",function(e){e.preventDefault(),$(this).toggleClass("active"),$(this).next("div").slideToggle(150)}),$(window).scroll(function(){150<=$(this).scrollTop()?$("#scroll-btn").fadeIn(200):$("#scroll-btn").fadeOut(200)}),$("#scroll-btn").click(function(e){e.preventDefault(),$("body,html").animate({scrollTop:0},500)}),$('a[data-toggle="tab"]').on("shown.bs.tab",function(e){$(".main-gallery-nav, .gallery").slick("setPosition")})});